SELECT c.* FROM tb_comment c INNER JOIN tb_video v ON v.id = c.video_id LEFT JOIN tb_comment_stats s ON s.comment_id = c.id WHERE v.user_id = #{userId} AND c.is_deleted = 0
AND c.content LIKE CONCAT('%', #{keyword}, '%')
AND c.video_id = #{videoId}
ORDER BY CASE WHEN #{sortType} = 2 THEN COALESCE(s.like_count, 0) END DESC, c.create_time DESC, c.id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM tb_comment c INNER JOIN tb_video v ON v.id = c.video_id WHERE v.user_id = #{userId} AND c.is_deleted = 0
AND c.content LIKE CONCAT('%', #{keyword}, '%')
AND c.video_id = #{videoId}
